/**
 * Loads the contributors using the GitHub service.
 */
public interface LoadContributors {

    /**
     * Performs requests to GitHub and loads and aggregates the contributors for all
     * repositories under the given organization.
     */
    default int loadContributorsSeq(String username, String password, String org)
        throws IOException {

        //Create the service to make the requests
        GitHubService service = createGitHubService(username, password);

        //Get all the repos under the given organization
        List<Repo> repos = service.getOrgReposCall(org).execute().body();
        if (repos == null) {
            System.err.println("Error making request to GitHub. Make sure token and organization name are correct.");
            return 0;
        } else if (repos.size() == 0) {
            System.out.println("0 repositories found in " + org + " organization, make sure your token is correct.");
            updateContributors(new ArrayList<>());
            return 0;
        } else {
            System.out.println("Found " + repos.size() + " repositories in " + org + " organization.");
        }

        //Get the contributors for each repo
        List<User> users = new ArrayList<>();
        for (Repo repo : repos) {
            List<User> tempUsers = service.getRepContributorsCall(org, repo.name).execute().body();
            if (tempUsers != null) {
                users.addAll(tempUsers);
                System.out.println("Found " + tempUsers.size() + " users in " + repo.name + " repository.");
            } else {
                System.err.println("Error making request to GitHub for repository " + repo.name);
            }
        }

        //Aggregate the number of contributions for each user
        System.out.println("Aggregating Results");
        List<User> aggregatedUsers = new ArrayList<>();
        for (User user: users) {
            if (aggregatedUsers.contains(user)) {
                aggregatedUsers.get(aggregatedUsers.indexOf(user)).contributions += user.contributions;
            } else {
                aggregatedUsers.add(user);
            }
        }

        //Sort the users in descending order of contributions
        aggregatedUsers.sort((o1, o2) -> o2.contributions - o1.contributions);
        System.out.println("Displaying Results");
        updateContributors(aggregatedUsers);
        return repos.size();
    }

    /**
     * Performs requests to GitHub and loads and aggregates the contributors for all
     * repositories under the given organization in parallel using futures, data-driven tasks, and streams.
     * 
     * Requirement: Use futures, data-driven tasks, and streams (not finish or async).
     * Requirement: UI must not freeze when loading data.
     */
    default int loadContributorsPar(String username, String password, String org)
        throws IOException {

        // Create the service to make the requests
        GitHubService service = createGitHubService(username, password);

        // Get all the repos under the given organization (Sequential API call)
        List<Repo> repos = service.getOrgReposCall(org).execute().body();
        if (repos == null || repos.isEmpty()) {
            updateContributors(new ArrayList<>());
            return 0;
        }

        // 1. FUTURES: Create futures for each repo's contributors to fetch them concurrently
        List<HjFuture<List<User>>> futures = new ArrayList<>();
        for (Repo repo : repos) {
            if (repo == null || repo.name == null) continue;
            final String repoName = repo.name;
            futures.add(future(() -> {
                try {
                    return service.getRepContributorsCall(org, repoName).execute().body();
                } catch (IOException e) {
                    System.err.println("Error fetching " + repoName);
                    return null;
                }
            }));
        }

        // 2. DATA-DRIVEN TASKS: Use futureAwait to wait for all fetching futures
        HjFuture<List<User>> aggregateFuture = futureAwait(futures, () -> {

            // 3. STREAMS: Use parallel streams for concurrent data aggregation
            return futures.stream()
                .parallel() // Concurrent processing of results
                .flatMap(f -> {
                    try {
                        List<User> users = f.get(); // Guaranteed not to suspend since futures are done
                        return (users != null) ? users.stream() : Stream.empty();
                    } catch (SuspendableException e) {
                        sneakyThrow(e);
                        return Stream.empty();
                    }
                })
                .filter(Objects::nonNull)
                .collect(Collectors.groupingByConcurrent(
                    u -> (u.login != null) ? u.login : "unknown",
                    Collectors.summingInt(u -> (u.contributions != null) ? u.contributions : 0)
                ))
                .entrySet().parallelStream()
                .map(entry -> new User(entry.getKey(), entry.getValue()))
                .sorted((o1, o2) -> Integer.compare(o2.contributions, o1.contributions))
                .collect(Collectors.toList());
        });

        // Get the final aggregated result
        List<User> aggregatedUsers;
        try {
            aggregatedUsers = aggregateFuture.get();
        } catch (SuspendableException e) {
            sneakyThrow(e);
            aggregatedUsers = new ArrayList<>(); // Unreachable
        }

        // Update UI/results
        updateContributors(aggregatedUsers);
        return repos.size();
    }

    /**
     * Sneaky throw helper to handle checked SuspendableException in contexts where it's not declared,
     * allowing the HJlib runtime to properly handle suspension points.
     */
    @SuppressWarnings("unchecked")
